import{_ as o,o as a,c as s,a2 as i}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse('{"title":"RFC-004 — Mission URL sharing: serialisation, back-button behaviour","description":"","frontmatter":{},"headers":[],"relativePath":"rfc/RFC-004.md","filePath":"rfc/RFC-004.md"}'),t={name:"rfc/RFC-004.md"};function n(r,e,l,c,d,h){return a(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="rfc-004-—-mission-url-sharing-serialisation-back-button-behaviour" tabindex="-1">RFC-004 — Mission URL sharing: serialisation, back-button behaviour <a class="header-anchor" href="#rfc-004-—-mission-url-sharing-serialisation-back-button-behaviour" aria-label="Permalink to &quot;RFC-004 — Mission URL sharing: serialisation, back-button behaviour&quot;">​</a></h1><blockquote><p>Status · Decided TA anchor · §components/router · §components/fly-screen · §components/missions-screen Closed by · ADR-024 (2026-04-29) Why this is an RFC · The fly and missions screens support URL-encoded state. What exactly is encoded, what happens on back navigation, and what&#39;s out of scope for v1 are open questions with real trade-offs.</p></blockquote><h2 id="the-question" tabindex="-1">The question <a class="header-anchor" href="#the-question" aria-label="Permalink to &quot;The question&quot;">​</a></h2><p>Two screens support URL params:</p><ol><li><code>/fly?mission=curiosity</code> — loads a specific mission arc</li><li><code>/missions?dest=MARS</code> — opens library with filter applied</li></ol><p>Open questions: what state is encoded, how does back-button work, what stays out of scope for v1?</p><h2 id="use-cases" tabindex="-1">Use cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use cases&quot;">​</a></h2><ul><li>&quot;FLY THIS MISSION&quot; in mission library navigates to <code>/fly?mission=curiosity</code></li><li>Shared link opens directly to a specific mission&#39;s arc</li><li>User presses back from fly screen — returns to missions with filter intact</li><li><code>/missions?dest=MARS&amp;status=ACTIVE</code> opens with both filters applied</li></ul><h2 id="goals" tabindex="-1">Goals <a class="header-anchor" href="#goals" aria-label="Permalink to &quot;Goals&quot;">​</a></h2><ul><li>Shared links work without session state</li><li>Back button feels natural</li><li>Params are human-readable in the URL</li><li>Forward-compatible — adding params doesn&#39;t break old links</li></ul><h2 id="constraints" tabindex="-1">Constraints <a class="header-anchor" href="#constraints" aria-label="Permalink to &quot;Constraints&quot;">​</a></h2><p>From ADR-013: History API routing via SvelteKit. Params in the query string of the URL (<code>/fly?mission=id</code>). <code>URLSearchParams</code> handles parsing; <code>$page.url.searchParams</code> exposes them in Svelte components.</p><h2 id="proposed-approach" tabindex="-1">Proposed approach <a class="header-anchor" href="#proposed-approach" aria-label="Permalink to &quot;Proposed approach&quot;">​</a></h2><p><strong>Encoded state:</strong></p><ul><li>Fly screen: <code>?mission=[id]</code> — mission ID. Absent = default ORRERY-1 scenario.</li><li>Missions screen: <code>?dest=[MARS|MOON]</code> and <code>?status=[ACTIVE|FLOWN|PLANNED]</code>. Combinable: <code>?dest=MARS&amp;status=ACTIVE</code>.</li><li>Nothing else encoded in v1 (porkchop range, camera angle, simulation time all reset on navigation).</li></ul><p><strong>Back button:</strong> <code>router.navigate()</code> pushes to hash history. Back/forward works naturally within session.</p><p><strong>Link generation:</strong> &quot;FLY THIS MISSION&quot; calls <code>router.navigate(&#39;fly&#39;, { mission: id })</code> → <code>/fly?mission=id</code>.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><p><strong>Encode simulation time in fly URL</strong> (<code>?mission=curiosity&amp;met=180</code>) — allows sharing a moment in the trajectory. Adds initialisation complexity (fast-forward to encoded time). Deferred to v2.</p><p><strong>Encode porkchop range in plan URL</strong> — useful for sharing a launch window analysis. Deferred to v2.</p><p><strong>No URL params</strong> — breaks the &quot;share this mission&quot; use case. Rejected.</p><h2 id="trade-offs" tabindex="-1">Trade-offs <a class="header-anchor" href="#trade-offs" aria-label="Permalink to &quot;Trade-offs&quot;">​</a></h2><p>v1 encodes mission ID and library filters only. Camera, simulation time, and porkchop configuration are not shared. This is an explicit scope decision.</p><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li>Should <code>?mission=invalid-id</code> fall back to ORRERY-1 or show an error state?</li><li>Should filter combinations be bookmarkable beyond the two proposed params?</li><li>Should <code>/fly?mission=curiosity&amp;met=180</code> be supported for deep-linking to a mission moment?</li></ol><h2 id="closing-evidence" tabindex="-1">Closing evidence <a class="header-anchor" href="#closing-evidence" aria-label="Permalink to &quot;Closing evidence&quot;">​</a></h2><p><code>/fly?mission=curiosity</code> loads Curiosity&#39;s arc. <code>/missions?dest=MARS</code> opens Mars filter. Back button returns to previous filtered state. Available at Slice 4 gate.</p><h2 id="how-this-closes" tabindex="-1">How this closes <a class="header-anchor" href="#how-this-closes" aria-label="Permalink to &quot;How this closes&quot;">​</a></h2><p>One ADR: URL encoding contract for mission and filter params.</p>',29)])])}const m=o(t,[["render",n]]);export{u as __pageData,m as default};
